const data = $input.first().json;
// Webhook typeVersion 2 anida el body; typeVersion 1 lo pone directo en $json
const userId = data.body?.userId ?? data.userId ?? null;
if (!userId) throw new Error('userId no recibido en el webhook. Verifica que el backend envíe { userId } en el body.');
return [{ json: { userId } }];

const tasks = $('Consultar Tareas de Supabase').first().json || [];
const userData = $('Consultar Usuario de Supabase').first().json || [];
const user = Array.isArray(userData) ? (userData[0] || {}) : (userData || {});

const today = new Date().toLocaleDateString('es-ES', {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

const prioEmoji = { urgente: '🔴', alta: '🟠', media: '🟡', baja: '🟢' };
const statusLabel = { pendiente: 'Pendiente', en_proceso: 'En proceso', finalizada: 'Finalizada' };

const taskArray = Array.isArray(tasks) ? tasks : [];
const taskList = taskArray.length > 0
  ? taskArray.map((t, i) => {
      const due = t.due_date ? new Date(t.due_date).toLocaleDateString('es-ES') : 'Sin fecha';
      const emoji = prioEmoji[t.priority] || '⚪';
      const status = statusLabel[t.status] || t.status;
      const desc = t.description ? `\n   📝 ${t.description}` : '';
      return `${i + 1}. ${emoji} ${t.title} | ${status} | Vence: ${due}${desc}`;
    }).join('\n')
  : 'No tienes tareas registradas aún.';

const systemPrompt = `Eres un asistente experto en productividad y organización personal. Ayudas a las personas a estructurar su día de forma clara, realista y motivadora.\n\nHoy es ${today}.\n\nCuando recibas las tareas del usuario:\n- Analiza prioridades (urgente > alta > media > baja) y fechas límite\n- Propón un horario o secuencia de tareas para hoy\n- Agrupa tareas relacionadas si las hay\n- Destaca las urgentes o próximas a vencer\n- Termina con un consejo motivacional breve\n\nUsa formato claro con secciones. Sé conciso y práctico.`;

const userName = user.full_name || user.first_name || user.email || 'Usuario';
const userPrompt = `Hola! Soy ${userName}. Aquí están mis tareas:\n\n${taskList}\n\n¿Puedes ayudarme a organizar mi rutina para hoy?`;

return [{ json: { systemPrompt, userPrompt } }];
